namespace sv_f8be9a5173a347cf9f502fe6b7481fa5.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@page "/settings"
@rendermode InteractiveServer
@using sv_f8be9a5173a347cf9f502fe6b7481fa5.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <!-- Left Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span class="nav-label">@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main Content Area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            <!-- Toast / Success Message -->
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                    <span>@_toastMessage</span>
                    <button class="btn-close btn-close-sm" @onclick="DismissToast"></button>
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* ───────────── Profile Section ───────────── *@

@{
    RenderFragment RenderProfileSection() =>
        @<div class="settings-section">
            <h3>Profile</h3>
            <p class="text-muted">Manage your personal information.</p>

            <div class="avatar-preview mb-4">
                <div class="avatar-image">
                    @if (!string.IsNullOrWhiteSpace(_editProfile.AvatarUrl))
                    {
                        <img src="@_editProfile.AvatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <span class="avatar-placeholder">👤</span>
                    }
                </div>
                <div class="avatar-url text-muted small mt-1">@_editProfile.AvatarUrl</div>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_editProfile.DisplayName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_editProfile.Email" />
            </div>

            <div class="mb-3">
                <label class="form-label">Avatar URL</label>
                <input type="url" class="form-control" @bind="_editProfile.AvatarUrl" />
            </div>

            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_editProfile.Bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </div>;
}

@* ───────────── Notifications Section ───────────── *@

@{
    RenderFragment RenderNotificationsSection() =>
        @<div class="settings-section">
            <h3>Notifications</h3>
            <p class="text-muted">Choose how you want to be notified.</p>

            <div class="toggle-group">
                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Email Notifications</div>
                        <div class="text-muted small">Receive updates via email</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               @bind="_editNotifications.EmailNotifications" />
                    </div>
                </div>

                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Push Notifications</div>
                        <div class="text-muted small">Receive push notifications in your browser</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               @bind="_editNotifications.PushNotifications" />
                    </div>
                </div>

                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Weekly Digest</div>
                        <div class="text-muted small">Get a weekly summary of activity</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               @bind="_editNotifications.WeeklyDigest" />
                    </div>
                </div>
            </div>

            <hr />

            <h5>Muted Channels</h5>
            <p class="text-muted small">Uncheck a channel to unmute it.</p>

            @if (_editNotifications.MutedChannels.Count == 0)
            {
                <p class="text-muted fst-italic">No channels available.</p>
            }
            else
            {
                <div class="channel-list">
                    @for (var i = 0; i < _allChannels.Count; i++)
                    {
                        var channel = _allChannels[i];
                        var isMuted = _editNotifications.MutedChannels.Contains(channel);
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{i}")"
                                   checked="@isMuted"
                                   @onchange="e => ToggleChannelMute(channel, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"ch-{i}")">@channel</label>
                        </div>
                    }
                </div>
            }

            <div class="mt-4">
                <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Preferences
                </button>
            </div>
        </div>;
}

@* ───────────── Security Section ───────────── *@

@{
    RenderFragment RenderSecuritySection() =>
        @<div class="settings-section">
            <h3>Security</h3>
            <p class="text-muted">Manage your account security.</p>

            <!-- Change Password Panel -->
            <div class="expandable-panel mb-4">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span class="fw-semibold">Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>

                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        @if (!string.IsNullOrEmpty(_passwordError))
                        {
                            <div class="alert alert-danger py-2">@_passwordError</div>
                        }
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="toggle-row mb-4">
                <div>
                    <div class="fw-semibold">Two-Factor Authentication</div>
                    <div class="text-muted small">
                        Status:
                        @if (_securitySettings?.TwoFactorEnabled == true)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-secondary">Disabled</span>
                        }
                    </div>
                    @if (_securitySettings?.LastPasswordChange.HasValue == true)
                    {
                        <div class="text-muted small mt-1">
                            Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </div>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@(_securitySettings?.TwoFactorEnabled ?? false)"
                           disabled />
                </div>
            </div>

            <!-- Active Sessions -->
            <h5>Active Sessions</h5>
            @if (_securitySettings?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (session != _securitySettings.Sessions.First())
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted fst-italic">No active sessions.</p>
            }

            <!-- Revoke Confirmation Dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop show"></div>
                <div class="modal show d-block" tabindex="-1">
                    <div class="modal-dialog modal-dialog-centered">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h5 class="modal-title">Revoke Session</h5>
                                <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                            </div>
                            <div class="modal-body">
                                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                                <p class="text-muted small">This will sign out that device immediately.</p>
                            </div>
                            <div class="modal-footer">
                                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                <button class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                    Revoke
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        </div>;
}

@* ───────────── Appearance Section ───────────── *@

@{
    RenderFragment RenderAppearanceSection() =>
        @<div class="settings-section">
            <h3>Appearance</h3>
            <p class="text-muted">Customize the look and feel.</p>

            <div class="row">
                <div class="col-lg-7">
                    <!-- Theme -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Theme</label>
                        <div class="d-flex gap-3">
                            @foreach (var theme in new[] { "Light", "Dark", "System" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="theme"
                                           id="@($"theme-{theme}")"
                                           value="@theme"
                                           checked="@(_editAppearance.Theme == theme)"
                                           @onchange="() => _editAppearance.Theme = theme" />
                                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                                </div>
                            }
                        </div>
                    </div>

                    <!-- Font Size -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Font Size</label>
                        <div class="d-flex gap-3">
                            @foreach (var size in new[] { "Small", "Medium", "Large" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="fontSize"
                                           id="@($"fs-{size}")"
                                           value="@size"
                                           checked="@(_editAppearance.FontSize == size)"
                                           @onchange="() => _editAppearance.FontSize = size" />
                                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                                </div>
                            }
                        </div>
                    </div>

                    <!-- Language -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Language</label>
                        <select class="form-select" @bind="_editAppearance.Language">
                            <option value="en">English</option>
                            <option value="es">Español</option>
                            <option value="fr">Français</option>
                            <option value="de">Deutsch</option>
                            <option value="ja">日本語</option>
                            <option value="zh">中文</option>
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="toggle-row mb-4">
                        <div>
                            <div class="fw-semibold">Compact Mode</div>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   @bind="_editAppearance.CompactMode" />
                        </div>
                    </div>

                    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save
                    </button>
                </div>

                <!-- Live Preview -->
                <div class="col-lg-5">
                    <div class="preview-card @GetPreviewClasses()">
                        <div class="preview-header">Live Preview</div>
                        <div class="preview-body">
                            <p class="preview-title">Sample Heading</p>
                            <p>This is how your content will look with the selected settings.</p>
                            <button class="preview-button">Sample Button</button>
                        </div>
                    </div>
                </div>
            </div>
        </div>;
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private readonly Dictionary<string, (string Icon, string Label)> _sections = new()
    {
        ["profile"] = ("👤", "Profile"),
        ["notifications"] = ("🔔", "Notifications"),
        ["security"] = ("🔒", "Security"),
        ["appearance"] = ("🎨", "Appearance"),
    };

    // ── Loading state ──
    private bool _loading = true;
    private bool _saving;

    // ── Toast ──
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile ──
    private UserProfile? _savedProfile;
    private ProfileForm _editProfile = new();

    // ── Notifications ──
    private NotificationPrefs? _savedNotifications;
    private NotificationsForm _editNotifications = new();
    private List<string> _allChannels = [];

    // ── Security ──
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = string.Empty;
    private string _newPassword = string.Empty;
    private string _confirmPassword = string.Empty;
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance ──
    private AppearanceSettings? _savedAppearance;
    private AppearanceForm _editAppearance = new();

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appearTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appearTask);

        _savedProfile = profileTask.Result;
        _editProfile = ProfileForm.FromRecord(_savedProfile);

        _savedNotifications = notifTask.Result;
        _editNotifications = NotificationsForm.FromRecord(_savedNotifications);
        _allChannels = [.. _savedNotifications.MutedChannels];

        _securitySettings = secTask.Result;

        _savedAppearance = appearTask.Result;
        _editAppearance = AppearanceForm.FromRecord(_savedAppearance);
    }

    // ── Section Navigation ──

    private void SetActiveSection(string section)
    {
        ActiveSection = section;
        DismissToast();
    }

    // ── Toast Helpers ──

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();

        try
        {
            await Task.Delay(4000, _toastCts.Token);
            DismissToast();
            StateHasChanged();
        }
        catch (TaskCanceledException)
        {
            // Toast was dismissed or replaced early.
        }
    }

    private void DismissToast()
    {
        _toastMessage = null;
        _toastCts?.Cancel();
    }

    // ── Profile ──

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var record = _editProfile.ToRecord();
            await SettingsService.SaveProfileAsync(record);
            _savedProfile = record;
            await ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error saving profile: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            _editProfile = ProfileForm.FromRecord(_savedProfile);
        }
    }

    // ── Notifications ──

    private void ToggleChannelMute(string channel, bool muted)
    {
        if (muted && !_editNotifications.MutedChannels.Contains(channel))
            _editNotifications.MutedChannels.Add(channel);
        else if (!muted)
            _editNotifications.MutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var record = _editNotifications.ToRecord();
            await SettingsService.SaveNotificationPrefsAsync(record);
            _savedNotifications = record;
            await ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error saving preferences: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Security ──

    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New passwords do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = _confirmPassword = _newPassword = string.Empty;
            _passwordPanelOpen = false;
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            await ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;

        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            _sessionToRevoke = null;
            await ShowToast("Session revoked.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error revoking session: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Appearance ──

    private string GetPreviewClasses()
    {
        var classes = new List<string>();

        classes.Add(_editAppearance.Theme switch
        {
            "Dark" => "preview-dark",
            "System" => "preview-system",
            _ => "preview-light",
        });

        classes.Add(_editAppearance.FontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md",
        });

        if (_editAppearance.CompactMode) classes.Add("preview-compact");

        return string.Join(' ', classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var record = _editAppearance.ToRecord();
            await SettingsService.SaveAppearanceAsync(record);
            _savedAppearance = record;
            await ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error saving appearance: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Mutable form models ──

    private sealed class ProfileForm
    {
        public string DisplayName { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string AvatarUrl { get; set; } = string.Empty;
        public string Bio { get; set; } = string.Empty;

        public static ProfileForm FromRecord(UserProfile p) => new()
        {
            DisplayName = p.DisplayName,
            Email = p.Email,
            AvatarUrl = p.AvatarUrl,
            Bio = p.Bio,
        };

        public UserProfile ToRecord() => new(DisplayName, Email, AvatarUrl, Bio);
    }

    private sealed class NotificationsForm
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = [];

        public static NotificationsForm FromRecord(NotificationPrefs n) => new()
        {
            EmailNotifications = n.EmailNotifications,
            PushNotifications = n.PushNotifications,
            WeeklyDigest = n.WeeklyDigest,
            MutedChannels = [.. n.MutedChannels],
        };

        public NotificationPrefs ToRecord() => new(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
    }

    private sealed class AppearanceForm
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "en";
        public bool CompactMode { get; set; }

        public static AppearanceForm FromRecord(AppearanceSettings a) => new()
        {
            Theme = a.Theme,
            FontSize = a.FontSize,
            Language = a.Language,
            CompactMode = a.CompactMode,
        };

        public AppearanceSettings ToRecord() => new(Theme, FontSize, Language, CompactMode);
    }
}

/* ── Dashboard layout ── */

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
}

/* ── Sidebar ── */

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 700;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    color: #495057;
    font-weight: 500;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.settings-nav-item:hover {
    background: #e9ecef;
}

.settings-nav-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
}

.nav-icon {
    font-size: 1.1rem;
}

/* ── Content area ── */

.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
    overflow-y: auto;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
}

/* ── Toast ── */

.settings-toast {
    position: absolute;
    top: 1rem;
    right: 1.5rem;
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.6rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.875rem;
    font-weight: 500;
    z-index: 100;
    animation: toast-in 0.25s ease-out;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
}

@keyframes toast-in {
    from { opacity: 0; transform: translateY(-8px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Avatar ── */

.avatar-preview {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
}

.avatar-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid #dee2e6;
}

.avatar-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
}

/* ── Toggle rows ── */

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-row:last-child {
    border-bottom: none;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
}

/* ── Expandable panel ── */

.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    overflow: hidden;
}

.expandable-header {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    text-align: left;
}

.expandable-header:hover {
    background: #e9ecef;
}

.expandable-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* ── Preview card ── */

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.25s ease;
}

.preview-header {
    padding: 0.6rem 1rem;
    font-weight: 600;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.04em;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-title {
    font-weight: 700;
    margin-bottom: 0.4rem;
}

.preview-button {
    padding: 0.35rem 0.9rem;
    border-radius: 0.25rem;
    border: none;
    font-weight: 500;
    cursor: default;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
    color: #495057;
}

.preview-light .preview-button {
    background: #0d6efd;
    color: #fff;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    color: #a6adc8;
    border-color: #45475a;
}

.preview-dark .preview-button {
    background: #89b4fa;
    color: #1e1e2e;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: #eef2ff;
    color: #495057;
}

.preview-system .preview-button {
    background: #6366f1;
    color: #fff;
}

/* Font size variants */
.preview-font-sm .preview-body { font-size: 0.8rem; }
.preview-font-md .preview-body { font-size: 0.95rem; }
.preview-font-lg .preview-body { font-size: 1.15rem; }

/* Compact variant */
.preview-compact .preview-header { padding: 0.35rem 0.75rem; }
.preview-compact .preview-body  { padding: 0.6rem 0.75rem; }
.preview-compact .preview-body p { margin-bottom: 0.2rem; }

namespace sv_f8be9a5173a347cf9f502fe6b7481fa5.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@page "/settings"
@rendermode InteractiveServer
@using sv_f8be9a5173a347cf9f502fe6b7481fa5.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <!-- Left Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span class="nav-label">@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main Content Area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            <!-- Toast / Success Message -->
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                    <span>@_toastMessage</span>
                    <button class="btn-close btn-close-sm" @onclick="DismissToast"></button>
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* ───────────── Profile Section ───────────── *@

@{
    RenderFragment RenderProfileSection() =>
        @<div class="settings-section">
            <h3>Profile</h3>
            <p class="text-muted">Manage your personal information.</p>

            <div class="avatar-preview mb-4">
                <div class="avatar-image">
                    @if (!string.IsNullOrWhiteSpace(_editProfile.AvatarUrl))
                    {
                        <img src="@_editProfile.AvatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <span class="avatar-placeholder">👤</span>
                    }
                </div>
                <div class="avatar-url text-muted small mt-1">@_editProfile.AvatarUrl</div>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_editProfile.DisplayName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_editProfile.Email" />
            </div>

            <div class="mb-3">
                <label class="form-label">Avatar URL</label>
                <input type="url" class="form-control" @bind="_editProfile.AvatarUrl" />
            </div>

            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_editProfile.Bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </div>;
}

@* ───────────── Notifications Section ───────────── *@

@{
    RenderFragment RenderNotificationsSection() =>
        @<div class="settings-section">
            <h3>Notifications</h3>
            <p class="text-muted">Choose how you want to be notified.</p>

            <div class="toggle-group">
                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Email Notifications</div>
                        <div class="text-muted small">Receive updates via email</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               @bind="_editNotifications.EmailNotifications" />
                    </div>
                </div>

                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Push Notifications</div>
                        <div class="text-muted small">Receive push notifications in your browser</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               @bind="_editNotifications.PushNotifications" />
                    </div>
                </div>

                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Weekly Digest</div>
                        <div class="text-muted small">Get a weekly summary of activity</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               @bind="_editNotifications.WeeklyDigest" />
                    </div>
                </div>
            </div>

            <hr />

            <h5>Muted Channels</h5>
            <p class="text-muted small">Uncheck a channel to unmute it.</p>

            @if (_editNotifications.MutedChannels.Count == 0)
            {
                <p class="text-muted fst-italic">No channels available.</p>
            }
            else
            {
                <div class="channel-list">
                    @for (var i = 0; i < _allChannels.Count; i++)
                    {
                        var channel = _allChannels[i];
                        var isMuted = _editNotifications.MutedChannels.Contains(channel);
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{i}")"
                                   checked="@isMuted"
                                   @onchange="e => ToggleChannelMute(channel, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"ch-{i}")">@channel</label>
                        </div>
                    }
                </div>
            }

            <div class="mt-4">
                <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Preferences
                </button>
            </div>
        </div>;
}

@* ───────────── Security Section ───────────── *@

@{
    RenderFragment RenderSecuritySection() =>
        @<div class="settings-section">
            <h3>Security</h3>
            <p class="text-muted">Manage your account security.</p>

            <!-- Change Password Panel -->
            <div class="expandable-panel mb-4">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span class="fw-semibold">Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>

                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        @if (!string.IsNullOrEmpty(_passwordError))
                        {
                            <div class="alert alert-danger py-2">@_passwordError</div>
                        }
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="toggle-row mb-4">
                <div>
                    <div class="fw-semibold">Two-Factor Authentication</div>
                    <div class="text-muted small">
                        Status:
                        @if (_securitySettings?.TwoFactorEnabled == true)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-secondary">Disabled</span>
                        }
                    </div>
                    @if (_securitySettings?.LastPasswordChange.HasValue == true)
                    {
                        <div class="text-muted small mt-1">
                            Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </div>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@(_securitySettings?.TwoFactorEnabled ?? false)"
                           disabled />
                </div>
            </div>

            <!-- Active Sessions -->
            <h5>Active Sessions</h5>
            @if (_securitySettings?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (session != _securitySettings.Sessions.First())
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted fst-italic">No active sessions.</p>
            }

            <!-- Revoke Confirmation Dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop show"></div>
                <div class="modal show d-block" tabindex="-1">
                    <div class="modal-dialog modal-dialog-centered">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h5 class="modal-title">Revoke Session</h5>
                                <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                            </div>
                            <div class="modal-body">
                                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                                <p class="text-muted small">This will sign out that device immediately.</p>
                            </div>
                            <div class="modal-footer">
                                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                <button class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                    Revoke
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        </div>;
}

@* ───────────── Appearance Section ───────────── *@

@{
    RenderFragment RenderAppearanceSection() =>
        @<div class="settings-section">
            <h3>Appearance</h3>
            <p class="text-muted">Customize the look and feel.</p>

            <div class="row">
                <div class="col-lg-7">
                    <!-- Theme -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Theme</label>
                        <div class="d-flex gap-3">
                            @foreach (var theme in new[] { "Light", "Dark", "System" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="theme"
                                           id="@($"theme-{theme}")"
                                           value="@theme"
                                           checked="@(_editAppearance.Theme == theme)"
                                           @onchange="() => _editAppearance.Theme = theme" />
                                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                                </div>
                            }
                        </div>
                    </div>

                    <!-- Font Size -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Font Size</label>
                        <div class="d-flex gap-3">
                            @foreach (var size in new[] { "Small", "Medium", "Large" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="fontSize"
                                           id="@($"fs-{size}")"
                                           value="@size"
                                           checked="@(_editAppearance.FontSize == size)"
                                           @onchange="() => _editAppearance.FontSize = size" />
                                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                                </div>
                            }
                        </div>
                    </div>

                    <!-- Language -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Language</label>
                        <select class="form-select" @bind="_editAppearance.Language">
                            <option value="en">English</option>
                            <option value="es">Español</option>
                            <option value="fr">Français</option>
                            <option value="de">Deutsch</option>
                            <option value="ja">日本語</option>
                            <option value="zh">中文</option>
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="toggle-row mb-4">
                        <div>
                            <div class="fw-semibold">Compact Mode</div>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   @bind="_editAppearance.CompactMode" />
                        </div>
                    </div>

                    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save
                    </button>
                </div>

                <!-- Live Preview -->
                <div class="col-lg-5">
                    <div class="preview-card @GetPreviewClasses()">
                        <div class="preview-header">Live Preview</div>
                        <div class="preview-body">
                            <p class="preview-title">Sample Heading</p>
                            <p>This is how your content will look with the selected settings.</p>
                            <button class="preview-button">Sample Button</button>
                        </div>
                    </div>
                </div>
            </div>
        </div>;
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private readonly Dictionary<string, (string Icon, string Label)> _sections = new()
    {
        ["profile"] = ("👤", "Profile"),
        ["notifications"] = ("🔔", "Notifications"),
        ["security"] = ("🔒", "Security"),
        ["appearance"] = ("🎨", "Appearance"),
    };

    // ── Loading state ──
    private bool _loading = true;
    private bool _saving;

    // ── Toast ──
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile ──
    private UserProfile? _savedProfile;
    private ProfileForm _editProfile = new();

    // ── Notifications ──
    private NotificationPrefs? _savedNotifications;
    private NotificationsForm _editNotifications = new();
    private List<string> _allChannels = [];

    // ── Security ──
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = string.Empty;
    private string _newPassword = string.Empty;
    private string _confirmPassword = string.Empty;
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance ──
    private AppearanceSettings? _savedAppearance;
    private AppearanceForm _editAppearance = new();

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appearTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appearTask);

        _savedProfile = profileTask.Result;
        _editProfile = ProfileForm.FromRecord(_savedProfile);

        _savedNotifications = notifTask.Result;
        _editNotifications = NotificationsForm.FromRecord(_savedNotifications);
        _allChannels = [.. _savedNotifications.MutedChannels];

        _securitySettings = secTask.Result;

        _savedAppearance = appearTask.Result;
        _editAppearance = AppearanceForm.FromRecord(_savedAppearance);
    }

    // ── Section Navigation ──

    private void SetActiveSection(string section)
    {
        ActiveSection = section;
        DismissToast();
    }

    // ── Toast Helpers ──

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();

        try
        {
            await Task.Delay(4000, _toastCts.Token);
            DismissToast();
            StateHasChanged();
        }
        catch (TaskCanceledException)
        {
            // Toast was dismissed or replaced early.
        }
    }

    private void DismissToast()
    {
        _toastMessage = null;
        _toastCts?.Cancel();
    }

    // ── Profile ──

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var record = _editProfile.ToRecord();
            await SettingsService.SaveProfileAsync(record);
            _savedProfile = record;
            await ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error saving profile: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            _editProfile = ProfileForm.FromRecord(_savedProfile);
        }
    }

    // ── Notifications ──

    private void ToggleChannelMute(string channel, bool muted)
    {
        if (muted && !_editNotifications.MutedChannels.Contains(channel))
            _editNotifications.MutedChannels.Add(channel);
        else if (!muted)
            _editNotifications.MutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var record = _editNotifications.ToRecord();
            await SettingsService.SaveNotificationPrefsAsync(record);
            _savedNotifications = record;
            await ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error saving preferences: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Security ──

    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New passwords do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = _confirmPassword = _newPassword = string.Empty;
            _passwordPanelOpen = false;
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            await ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;

        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            _sessionToRevoke = null;
            await ShowToast("Session revoked.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error revoking session: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Appearance ──

    private string GetPreviewClasses()
    {
        var classes = new List<string>();

        classes.Add(_editAppearance.Theme switch
        {
            "Dark" => "preview-dark",
            "System" => "preview-system",
            _ => "preview-light",
        });

        classes.Add(_editAppearance.FontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md",
        });

        if (_editAppearance.CompactMode) classes.Add("preview-compact");

        return string.Join(' ', classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var record = _editAppearance.ToRecord();
            await SettingsService.SaveAppearanceAsync(record);
            _savedAppearance = record;
            await ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error saving appearance: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Mutable form models ──

    private sealed class ProfileForm
    {
        public string DisplayName { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string AvatarUrl { get; set; } = string.Empty;
        public string Bio { get; set; } = string.Empty;

        public static ProfileForm FromRecord(UserProfile p) => new()
        {
            DisplayName = p.DisplayName,
            Email = p.Email,
            AvatarUrl = p.AvatarUrl,
            Bio = p.Bio,
        };

        public UserProfile ToRecord() => new(DisplayName, Email, AvatarUrl, Bio);
    }

    private sealed class NotificationsForm
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = [];

        public static NotificationsForm FromRecord(NotificationPrefs n) => new()
        {
            EmailNotifications = n.EmailNotifications,
            PushNotifications = n.PushNotifications,
            WeeklyDigest = n.WeeklyDigest,
            MutedChannels = [.. n.MutedChannels],
        };

        public NotificationPrefs ToRecord() => new(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
    }

    private sealed class AppearanceForm
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "en";
        public bool CompactMode { get; set; }

        public static AppearanceForm FromRecord(AppearanceSettings a) => new()
        {
            Theme = a.Theme,
            FontSize = a.FontSize,
            Language = a.Language,
            CompactMode = a.CompactMode,
        };

        public AppearanceSettings ToRecord() => new(Theme, FontSize, Language, CompactMode);
    }
}

