toolArgs.file_text:
/* ── Dashboard layout ── */

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
}

/* ── Sidebar ── */

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 700;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    color: #495057;
    font-weight: 500;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.settings-nav-item:hover {
    background: #e9ecef;
}

.settings-nav-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
}

.nav-icon {
    font-size: 1.1rem;
}

/* ── Content area ── */

.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
    overflow-y: auto;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
}

/* ── Toast ── */

.settings-toast {
    position: absolute;
    top: 1rem;
    right: 1.5rem;
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.6rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.875rem;
    font-weight: 500;
    z-index: 100;
    animation: toast-in 0.25s ease-out;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
}

@keyframes toast-in {
    from { opacity: 0; transform: translateY(-8px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Avatar ── */

.avatar-preview {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
}

.avatar-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid #dee2e6;
}

.avatar-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
}

/* ── Toggle rows ── */

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-row:last-child {
    border-bottom: none;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
}

/* ── Expandable panel ── */

.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    overflow: hidden;
}

.expandable-header {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    text-align: left;
}

.expandable-header:hover {
    background: #e9ecef;
}

.expandable-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* ── Preview card ── */

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.25s ease;
}

.preview-header {
    padding: 0.6rem 1rem;
    font-weight: 600;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.04em;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-title {
    font-weight: 700;
    margin-bottom: 0.4rem;
}

.preview-button {
    padding: 0.35rem 0.9rem;
    border-radius: 0.25rem;
    border: none;
    font-weight: 500;
    cursor: default;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
    color: #495057;
}

.preview-light .preview-button {
    background: #0d6efd;
    color: #fff;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    color: #a6adc8;
    border-color: #45475a;
}

.preview-dark .preview-button {
    background: #89b4fa;
    color: #1e1e2e;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: #eef2ff;
    color: #495057;
}

.preview-system .preview-button {
    background: #6366f1;
    color: #fff;
}

/* Font size variants */
.preview-font-sm .preview-body { font-size: 0.8rem; }
.preview-font-md .preview-body { font-size: 0.95rem; }
.preview-font-lg .preview-body { font-size: 1.15rem; }

/* Compact variant */
.preview-compact .preview-header { padding: 0.35rem 0.75rem; }
.preview-compact .preview-body  { padding: 0.6rem 0.75rem; }
.preview-compact .preview-body p { margin-bottom: 0.2rem; }

