+    to   { opacity: 1; transform: translateY(0); }
+}
+
+/* ── Avatar ── */
+
+.avatar-preview {
+    display: flex;
+    flex-direction: column;
+    align-items: flex-start;
+}
+
+.avatar-image {
+    width: 80px;
+    height: 80px;
+    border-radius: 50%;
+    overflow: hidden;
+    background: #e9ecef;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    border: 2px solid #dee2e6;
+}
+
+.avatar-image img {
+    width: 100%;
+    height: 100%;
+    object-fit: cover;
+}
+
+.avatar-placeholder {
+    font-size: 2rem;
+}
+
+/* ── Toggle rows ── */
+
+.toggle-group {
+    display: flex;
+    flex-direction: column;
+    gap: 0;
+}
+
+.toggle-row {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 0.75rem 0;
+    border-bottom: 1px solid #f0f0f0;
+}
+
+.toggle-row:last-child {
+    border-bottom: none;
+}
+
+.channel-list {
+    display: flex;
+    flex-direction: column;
+    gap: 0.4rem;
+}
+
+/* ── Expandable panel ── */
+
+.expandable-panel {
+    border: 1px solid #dee2e6;
+    border-radius: 0.375rem;
+    overflow: hidden;
+}
+
+.expandable-header {
+    width: 100%;
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 0.75rem 1rem;
+    background: #f8f9fa;
+    border: none;
+    cursor: pointer;
+    text-align: left;
+}
+
+.expandable-header:hover {
+    background: #e9ecef;
+}
+
+.expandable-body {
+    padding: 1rem;
+    border-top: 1px solid #dee2e6;
+}
+
+/* ── Preview card ── */
+
+.preview-card {
+    border: 1px solid #dee2e6;
+    border-radius: 0.5rem;
+    overflow: hidden;
+    transition: all 0.25s ease;
+}
+
+.preview-header {
+    padding: 0.6rem 1rem;
+    font-weight: 600;
+    font-size: 0.8rem;
+    text-transform: uppercase;
+    letter-spacing: 0.04em;
+    border-bottom: 1px solid #dee2e6;
+}
+
+.preview-body {
+    padding: 1rem;
+}
+
+.preview-title {
+    font-weight: 700;
+    margin-bottom: 0.4rem;
+}
+
+.preview-button {
+    padding: 0.35rem 0.9rem;
+    border-radius: 0.25rem;
+    border: none;
+    font-weight: 500;
+    cursor: default;
+}
+
+/* Theme variants */
+.preview-light {
+    background: #ffffff;
+    color: #212529;
+}
+
+.preview-light .preview-header {
+    background: #f8f9fa;
+    color: #495057;
+}
+
+.preview-light .preview-button {
+    background: #0d6efd;
+    color: #fff;
+}
+
+.preview-dark {
+    background: #1e1e2e;
+    color: #cdd6f4;
+    border-color: #45475a;
+}
+
+.preview-dark .preview-header {
+    background: #181825;
+    color: #a6adc8;
+    border-color: #45475a;
+}
+
+.preview-dark .preview-button {
+    background: #89b4fa;
+    color: #1e1e2e;
+}
+
+.preview-system {
+    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
+    color: #212529;
+}
+
+.preview-system .preview-header {
+    background: #eef2ff;
+    color: #495057;
+}
+
+.preview-system .preview-button {
+    background: #6366f1;
+    color: #fff;
+}
+
+/* Font size variants */
+.preview-font-sm .preview-body { font-size: 0.8rem; }
+.preview-font-md .preview-body { font-size: 0.95rem; }
+.preview-font-lg .preview-body { font-size: 1.15rem; }
+
+/* Compact variant */
+.preview-compact .preview-header { padding: 0.35rem 0.75rem; }
+.preview-compact .preview-body  { padding: 0.6rem 0.75rem; }
+.preview-compact .preview-body p { margin-bottom: 0.2rem; }
+
